-- tedw_release_summary
VALUES (
'
<span style="background-color: #9D0208; color: white; font-weight: bold; font-size: 18px; padding: 5px; display: inline-block; text-decoration: underline;">Release Summary - 02/10/2025 :</span>
<h4 style="margin-top: 0;">This release includes the following:</h4>
<ol>
    <li>Enhancements - 5
        <ul>
			<li>EDW claims data model updates (both additions and deletions of columns from tclaim, tclaim_feature, tclaim_transaction, tclaim_payment, tclaim_note, tclaim_summary and tclaim_feature_summary tables).  Refer below table for details. </li>
			<li>Created and made necessary updates to Policy Search API, Policy Webhook and Financial Transactions API integrations for snapsheet. </li>
			<li>Various one time data fixes associated with eBao to Snapsheet Claims Migration. </li>
			1) Updated Metal tables to reflect appropriate snapsheet loss types.<br>
			2) Updated original_policy_effective_dt in tpolicy table for 2 policies.<br>
			3) Removed 7 duplicate claim transactions from tclaim_transaction table.<br>
			4) Applied a onetime data fix for a few claims in tclaim table to remove special characters from policy number.<br>
			5) Applied a onetime data fix to default timestamp to 12PM for datetimeofloss and datetimeofnotification columns.<br>
			6) Updated claim loss date for 15 claims based on user request.<br>
			7) Updated losstype for 1600 auto claims which had both cause_of_loss and sub_cause_of_loss as "Other".<br>
			8) Updated CAT code for one claim.<br>
			9) Updated underwriting company for 4 claims.
			<li>Added Metal 2/7 release related 3 new columns (source_of_water, source_of_fire, include_in_rating_override_in). </li>
			<li>Backfilled yacht data for hubspot quote and customer feeds. </li>
		</ul>
    </li>
    <li>Bug tickets - 1
        <ul>
			<li>Resolved 1 ticket associated with updating billing account for one policy. This is just a onetime datafix.</li>
		</ul>
    </li>
</ol>
'
,'Yes'
,'2025-02-10'
,getdate()
,getdate()
)
;

-- tedw_release_note
